@app.post("/v1/models/upload", response_model=UploadResponse)
async def upload_model(request: Request, file: UploadFile = File(...)):
    tenant_id = _get_tenant_id_from_request(request)
    _enforce_limits(tenant_id)

    if not file.filename:
        raise HTTPException(status_code=400, detail="Missing filename")

    model_id = uuid.uuid4().hex
    path = _model_path(tenant_id, model_id)

    size = 0
    try:
        with open(path, "wb") as out:
            while True:
                chunk = await file.read(1024 * 1024)
                if not chunk:
                    break
                size += len(chunk)
                if size > MAX_UPLOAD_BYTES:
                    raise HTTPException(status_code=413, detail="Upload too large")
                out.write(chunk)
    finally:
        await file.close()

    try:
        model_obj = _load_model_from_disk(path)
    except Exception:
        try:
            os.remove(path)
        except Exception:
            pass
        raise HTTPException(status_code=400, detail="Failed to deserialize model")

    with _lock:
        tenant_models = _models.setdefault(tenant_id, {})
        tenant_models[model_id] = {
            "model": model_obj,
            "path": path,
            "filename": file.filename,
            "size_bytes": size,
            "created_at": time.time(),
            "last_access": time.time(),
        }

    return UploadResponse(tenant_id=tenant_id, model_id=model_id, filename=file.filename, size_bytes=size)


@app.get("/v1/models")
async def list_models(request: Request):
    tenant_id = _get_tenant_id_from_request(request)
    with _lock:
        tenant_models = _models.get(tenant_id, {})
        items = []
        for model_id, entry in tenant_models.items():
            items.append(
                {
                    "model_id": model_id,
                    "filename": entry.get("filename"),
                    "size_bytes": entry.get("size_bytes"),
                    "created_at": entry.get("created_at"),
                    "last_access": entry.get("last_access"),
                }
            )
    return {"tenant_id": tenant_id, "models": items}


@app.delete("/v1/models/{model_id}")
async def delete_model(request: Request, model_id: str):
    tenant_id = _get_tenant_id_from_request(request)
    path = _model_path(tenant_id, model_id)

    with _lock:
        tenant_models = _models.get(tenant_id, {})
        existed = model_id in tenant_models
        tenant_models.pop(model_id, None)
        if not tenant_models and tenant_id in _models:
            _models.pop(tenant_id, None)

    try:
        if os.path.exists(path):
            os.remove(path)
    except Exception:
        pass

    if not existed and not os.path.exists(path):
        raise HTTPException(status_code=404, detail="Model not found")

    return {"tenant_id": tenant_id, "model_id": model_id, "deleted": True}


def _invoke_model(model: Any, inputs: Any, method: Optional[str], kwargs: Optional[Dict[str, Any]]) -> Any:
    kwargs = kwargs or {}
    if method:
        fn = getattr(model, method, None)
        if not callable(fn):
            raise HTTPException(status_code=400, detail=f"Model has no callable method '{method}'")
        return fn(inputs, **kwargs)

    predict = getattr(model, "predict", None)
    if callable(predict):
        return predict(inputs, **kwargs)

    if callable(model):
        return model(inputs, **kwargs)

    raise HTTPException(status_code=400, detail="Model is not callable and has no predict method")


@app.post("/v1/models/{model_id}/predict", response_model=PredictResponse)
async def predict(request: Request, model_id: str, body: PredictRequest):
    tenant_id = _get_tenant_id_from_request(request)
    entry = _get_model_entry(tenant_id, model_id)
    model = entry["model"]

    try:
        output = _invoke_model(model, body.inputs, body.method, body.kwargs)
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Inference error: {type(e).__name__}")

    return PredictResponse(tenant_id=tenant_id, model_id=model_id, output=output)


